  1→<script lang="ts">
  2→	import { listMCPServers, deleteMCPServer } from '$lib/api';
  3→	import { onMount } from 'svelte';
  4→
  5→	let servers = $state<any[]>([]);
  6→	let loading = $state(true);
  7→	let error = $state('');
  8→	let deleting = $state<string | null>(null);
  9→
 10→	async function load() {
 11→		try {
 12→			const data = await listMCPServers();
 13→			servers = data.items || [];
 14→		} catch (e: any) {
 15→			error = e.message;
 16→		} finally {
 17→			loading = false;
 18→		}
 19→	}
 20→
 21→	onMount(() => {
 22→		load();
 23→		const interval = setInterval(load, 5000);
 24→		return () => clearInterval(interval);
 25→	});
 26→
 27→	function statusColor(status: string) {
 28→		switch (status) {
 29→			case 'running': return 'var(--green)';
 30→			case 'error': return 'var(--red)';
 31→			default: return 'var(--text-muted)';
 32→		}
 33→	}
 34→
 35→	function modeColor(mode: string) {
 36→		return mode === 'remote' ? 'var(--orange)' : 'var(--accent)';
 37→	}
 38→
 39→	async function handleDelete(e: Event, id: string, name: string) {
 40→		e.preventDefault();
 41→		e.stopPropagation();
 42→		if (!confirm(`Remove server "${name}"? This cannot be undone.`)) return;
 43→		deleting = id;
 44→		try {
 45→			await deleteMCPServer(id);
 46→			await load();
 47→		} catch (err: any) {
 48→			error = err.message;
 49→		} finally {
 50→			deleting = null;
 51→		}
 52→	}
 53→</script>
