  1→<script lang="ts">
  2→	import { page } from '$app/stores';
  3→	import { getApproval, getIntent, approveRequest, denyRequest } from '$lib/api';
  4→	import { onMount } from 'svelte';
  5→
  6→	let approval = $state<any>(null);
  7→	let intent = $state<any>(null);
  8→	let loading = $state(true);
  9→	let error = $state('');
 10→	let actionResult = $state('');
 11→	let acting = $state(false);
 12→	let denyReason = $state('');
 13→
 14→	const id = $derived($page.params.id ?? '');
 15→
 16→	async function load() {
 17→		if (!id) return;
 18→		try {
 19→			approval = await getApproval(id);
 20→			if (approval.intent_id) {
 21→				intent = await getIntent(approval.intent_id);
 22→			}
 23→		} catch (e: any) {
 24→			error = e.message;
 25→		} finally {
 26→			loading = false;
 27→		}
 28→	}
 29→
 30→	onMount(() => { load(); });
 31→
 32→	async function handleApprove() {
 33→		acting = true;
 34→		try {
 35→			const result = await approveRequest(id);
 36→			actionResult = `Approved. Grant ID: ${result.execution_grant_id}`;
 37→			await load();
 38→		} catch (e: any) {
 39→			actionResult = `Error: ${e.message}`;
 40→		} finally {
 41→			acting = false;
 42→		}
 43→	}
 44→
 45→	async function handleDeny() {
 46→		if (!denyReason.trim()) {
 47→			actionResult = 'Please provide a reason for denial.';
 48→			return;
 49→		}
 50→		acting = true;
 51→		try {
 52→			await denyRequest(id, denyReason);
 53→			actionResult = 'Denied.';
 54→			await load();
 55→		} catch (e: any) {
 56→			actionResult = `Error: ${e.message}`;
 57→		} finally {
 58→			acting = false;
 59→		}
 60→	}
 61→
 62→	function statusColor(status: string) {
 63→		switch (status) {
 64→			case 'pending': return 'var(--yellow)';
 65→			case 'approved': return 'var(--green)';
 66→			case 'denied': return 'var(--red)';
 67→			case 'modified': return 'var(--orange)';
 68→			default: return 'var(--text-muted)';
 69→		}
 70→	}
