 72→	function riskColor(level: string) {
 73→		switch (level) {
 74→			case 'low': return 'var(--green)';
 75→			case 'medium': return 'var(--yellow)';
 76→			case 'high': return 'var(--orange)';
 77→			case 'critical': return 'var(--red)';
 78→			default: return 'var(--text-muted)';
 79→		}
 80→	}
