  1→<script lang="ts">
  2→	import { searchMarketplace, installMarketplaceServer, setMCPServerCredential } from '$lib/api';
  3→	import { onMount } from 'svelte';
  4→
  5→	function clickOutside(node: HTMLElement, callback: () => void) {
  6→		function handleClick(e: MouseEvent) {
  7→			if (!node.contains(e.target as Node)) callback();
  8→		}
  9→		document.addEventListener('click', handleClick, true);
 10→		return { destroy() { document.removeEventListener('click', handleClick, true); } };
 11→	}
 12→
 13→	let servers = $state<any[]>([]);
 14→	let loading = $state(true);
 15→	let error = $state('');
 16→	let query = $state('');
 17→	let installing = $state<string | null>(null);
 18→	let installResult = $state<any>(null);
 19→	let credentialValues = $state<Record<string, string>>({});
 20→	let credError = $state('');
 21→	let credSaving = $state(false);
 22→	let debounceTimer: ReturnType<typeof setTimeout>;
 23→	let selectedVersions = $state<Record<string, string>>({});
 24→	let expandedInstall = $state<string | null>(null);
 25→
 26→	async function load(q?: string) {
 27→		try {
 28→			const data = await searchMarketplace(q || undefined);
 29→			servers = data.items || [];
 30→		} catch (e: any) {
 31→			error = e.message;
 32→		} finally {
 33→			loading = false;
 34→		}
 35→	}
 36→
 37→	function handleInput() {
 38→		clearTimeout(debounceTimer);
 39→		debounceTimer = setTimeout(() => load(query), 300);
 40→	}
 41→
 42→	async function handleInstall(registryId: string) {
 43→		installing = registryId;
 44→		expandedInstall = null;
 45→		try {
 46→			const result = await installMarketplaceServer(registryId);
 47→			if (result.required_credentials?.length > 0) {
 48→				installResult = result;
 49→				credentialValues = {};
 50→			} else {
 51→				await load(query || undefined);
 52→			}
 53→		} catch (e: any) {
 54→			error = e.message;
 55→		} finally {
 56→			installing = null;
 57→		}
 58→	}
 59→
 60→	async function handleSaveCredentials() {
 61→		credSaving = true;
 62→		credError = '';
 63→		try {
