187→			</div>
188→			<button
189→				onclick={handleSetCredential}
190→				disabled={credSaving}
191→				style="padding: 0.45rem 0.85rem; background: var(--accent); color: #fff; border: none; border-radius: 6px; cursor: pointer; font-size: 0.85rem;"
192→			>
193→				{credSaving ? 'Saving...' : 'Save'}
194→			</button>
195→		</div>
196→		{#if credResult}
197→			<p style="margin-top: 0.5rem; font-size: 0.8rem; color: {credResult.startsWith('Error') ? 'var(--red)' : 'var(--green)'};">{credResult}</p>
198→		{/if}
199→	</div>
200→
201→	<!-- Danger Zone -->
202→	<div style="padding: 1rem; border: 1px solid var(--red); border-radius: 8px; background: var(--bg-card);">
203→		<div style="font-weight: 600; margin-bottom: 0.5rem; color: var(--red);">Danger Zone</div>
204→		<button
205→			onclick={handleDelete}
206→			disabled={deleting}
207→			style="padding: 0.4rem 0.85rem; background: var(--red); color: #fff; border: none; border-radius: 6px; cursor: pointer; font-size: 0.85rem;"
208→		>
209→			{deleting ? 'Removing...' : 'Delete Server'}
210→		</button>
211→	</div>
212→{/if}
